import React, { useState } from 'react';
import CameraForm from './CameraForm';
import './CameraManagement.css';

function CameraManagement() {
  const [activeTab, setActiveTab] = useState('cameras');
  const [selectedCamera, setSelectedCamera] = useState(null);
  const [cameras, setCameras] = useState([]);
  const [showZoneDesigner, setShowZoneDesigner] = useState(false);

  // Chỉ giữ lại tab cameras nếu cần
  const tabs = [
    { id: 'cameras', label: '📷 Cameras', icon: '📹' },

  ];

  return (
    <div className="camera-management">
      {/* Sidebar */}
      <div className="sidebar">
        <div className="logo">
          <h2>Camera Admin</h2>
          <span className="version">v2.0</span>
        </div>

        <nav className="nav-menu">
          {tabs.map(tab => (
            <button
              key={tab.id}
              className={`nav-item ${activeTab === tab.id ? 'active' : ''}`}
              onClick={() => setActiveTab(tab.id)}
            >
              <span className="nav-icon">{tab.icon}</span>
              <span className="nav-label">{tab.label}</span>
            </button>
          ))}
        </nav>

        <div className="sidebar-footer">
          <div className="server-status">
            <span className="status-dot"></span>
            <span>Server: Online</span>
          </div>
          <div className="camera-stats">
            <small>Total: {cameras.length} cameras</small>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="main-content">
        {/* Header */}
        <div className="content-header">
          <h1>Camera Management</h1>
          <div className="header-actions">
            <button 
              className="btn-primary"
              onClick={() => setShowZoneDesigner(true)}
            >
              + New Camera
            </button>
          </div>
        </div>

        {/* Content Area */}
        <div className="content-area">
          {activeTab === 'cameras' && (
            <div className="cameras-view">
              {cameras.length > 0 ? (
                <CameraList 
                  cameras={cameras}
                  setCameras={setCameras}
                  onSelectCamera={(cam) => setSelectedCamera(cam)}
                />
              ) : (
                <div className="empty-state">
                  <p>Chưa có camera nào. Click "New Camera" để thêm mới.</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Quick Action Modal */}
      {showZoneDesigner && (
        <div className="modal-overlay">
          <div className="modal-content">
            <CameraForm 
              onSubmit={(data) => {
                setCameras([...cameras, data]);
                setShowZoneDesigner(false);
              }}
              onClose={() => setShowZoneDesigner(false)}
            />
          </div>
        </div>
      )}
    </div>
  );
}

export default CameraManagement;
